SELECT CAST(id AS CHAR) AS `key` ,name AS `value` FROM fx_economic_indicator WHERE deleted = 0
AND country_code = #{countryCode}
ORDER BY name

SELECT COUNT(id)
FROM fx_economic_indicator
WHERE deleted = 0

  AND importance = #{importance}


  AND country_code = #{countryCode}


  AND name LIKE '%${name}%'

SELECT t.id AS id ,t.country_code AS countryCode ,t.name AS name ,t.importance AS importance ,t.description AS description ,t.unit_of_value AS unitOfValue ,c.name AS countryName ,c.name_short AS countryNameShort FROM fx_economic_indicator t INNER JOIN fx_country c ON c.code = t.country_code WHERE t.deleted = 0
AND t.importance = #{importance}
AND t.country_code = #{countryCode}
AND t.name LIKE '%${name}%'
ORDER BY c.sort_order, t.id
LIMIT 0, #{size} LIMIT #{offset}, #{size}

SELECT EXISTS (
  SELECT *
  FROM fx_economic_indicator
  WHERE
    country_code = #{countryCode}
    AND name = #{name}
)

mapper.update:
UPDATE fx_economic_indicator
SET
   name         = #{indicator.name}
  ,importance   = #{indicator.importance}
  ,country_code = #{indicator.countryCode}
  ,description  = #{indicator.description}
  ,unit_of_value = #{indicator.unitOfValue}
  ,updated_at   = #{indicator.updatedAt}
  ,updated_by   = #{indicator.updatedBy}
WHERE
  id           = #{indicator.id}
  AND country_code = #{countryCode}
